
'use client';

import React, { useState, useEffect, useRef } from 'react';
import { useSearchParams, useRouter } from 'next/navigation';
import { useToast } from '@/hooks/use-toast';
import ImageUploader from '@/components/app/image-uploader';
import { createKissVideoAction } from '@/app/actions';
import type { CreateKissVideoActionInput } from '@/app/actions';
import { Button } from '@/components/ui/button';
import { Loader2, Wand2, ArrowLeft, Eye, Download, Info } from 'lucide-react';
import { Progress } from "@/components/ui/progress";
import Image from 'next/image';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import type { UploadMode } from '@/components/app/image-uploader';
import SubscriptionDialog from '@/components/app/subscription-dialog';
import { useAuth } from '@/contexts/auth-context';
import { checkUserSubscription } from '@/lib/firebase/db';
import type { UserProfile } from '@/lib/firebase/types';

type AppState = 'form' | 'loading' | 'result' | 'teaser';
type LoadingReason = 'generating' | 'configuring' | 'teaser';

function PageContent() {
  const { user, loading: authLoading } = useAuth();
  const searchParams = useSearchParams();
  const router = useRouter();
  const [appState, setAppState] = useState<AppState>('form');
  const [loadingReason, setLoadingReason] = useState<LoadingReason>('generating');
  const [uploadMode, setUploadMode] = useState<UploadMode>('two');
  const [image1, setImage1] = useState<string | null>(null);
  const [image2, setImage2] = useState<string | null>(null);
  const [sourceImageUrl, setSourceImageUrl] = useState<string | null>(null);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [canGenerate, setCanGenerate] = useState(false);
  const [progress, setProgress] = useState(0);
  const [isSubDialogOpen, setIsSubDialogOpen] = useState(false);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const { toast } = useToast();
  const hasTriggeredPostPaymentRef = useRef(false);
  const teaserTimeoutRef = useRef<NodeJS.Timeout | null>(null);
  const progressIntervalRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    // This effect handles the post-payment redirection.
    // It's designed to trigger only once.
    if (searchParams.get('paid') === 'true' && !user && !authLoading && !hasTriggeredPostPaymentRef.current) {
        hasTriggeredPostPaymentRef.current = true;
        // Save the image data before redirecting to login
        sessionStorage.setItem('pendingGeneration', 'true');
        router.push('/login?paid=true');
    }
    
    // Once the user is logged in, if they came from the payment flow, we can trigger generation.
    if (user && sessionStorage.getItem('pendingGeneration') === 'true' && sessionStorage.getItem('paidAction') !== 'true') {
        sessionStorage.setItem('paidAction', 'true'); // Prevent re-triggering
        const savedMode = sessionStorage.getItem('uploadMode') as UploadMode | null;
        const savedImage1 = sessionStorage.getItem('image1');
        const savedImage2 = sessionStorage.getItem('image2');

        if (savedMode && savedImage1) {
            console.log("Found saved images, starting real generation after payment...");
            startRealGeneration(savedImage1, savedImage2, savedMode);
        }
    } else if (user && sessionStorage.getItem('pendingTeaserGeneration') === 'true') {
        sessionStorage.removeItem('pendingTeaserGeneration');
        const savedMode = sessionStorage.getItem('uploadMode') as UploadMode | null;
        const savedImage1 = sessionStorage.getItem('image1');
        const savedImage2 = sessionStorage.getItem('image2');

        if (savedMode && savedImage1) {
            // Restore state from session storage and then trigger teaser flow
            setUploadMode(savedMode);
            setImage1(savedImage1);
            if(savedImage2) setImage2(savedImage2);
            // We set another flag to trigger the effect that depends on the images being set
            sessionStorage.setItem('isReadyForTeaser', 'true');
        }
    }
  }, [searchParams, user, authLoading, router]);

  useEffect(() => {
    // This effect will run once the images are restored in the state
    if (sessionStorage.getItem('isReadyForTeaser') === 'true' && image1) {
        sessionStorage.removeItem('isReadyForTeaser');
        console.log("Images restored, starting teaser flow now.");
        handleTeaserFlow();
    }
  }, [image1, image2, uploadMode]); // Rerun if image2 changes too


  useEffect(() => {
    async function fetchUserProfile() {
      if (user) {
        const profile = await checkUserSubscription(user.uid);
        setUserProfile(profile);
      } else {
        setUserProfile(null);
      }
    }
    fetchUserProfile();
  }, [user]);

  useEffect(() => {
    const isReady = image1 && (uploadMode === 'single' || image2);
    setCanGenerate(!!isReady);
  }, [image1, image2, uploadMode]);

  useEffect(() => {
    if (appState !== 'loading') {
      if (progressIntervalRef.current) {
        clearInterval(progressIntervalRef.current);
        progressIntervalRef.current = null;
      }
      if (teaserTimeoutRef.current) {
        clearTimeout(teaserTimeoutRef.current);
        teaserTimeoutRef.current = null;
      }
    }
  }, [appState]);
  
  const startRealGeneration = async (
    img1: string,
    img2: string | null,
    mode: UploadMode
  ) => {
    if (!user) {
      toast({ variant: 'destructive', title: 'User not found', description: 'Could not start video generation.' });
      setAppState('form');
      return;
    }
    setAppState('loading');
    setLoadingReason('generating');
    setProgress(0);

    const duration = 40000; // Estimated duration
    const updateInterval = 100; // Update every 100ms
    const totalSteps = duration / updateInterval;
    let currentStep = 0;
    
    progressIntervalRef.current = setInterval(() => {
        currentStep++;
        const newProgress = Math.min((currentStep / totalSteps) * 100, 95);
        setProgress(newProgress);
    }, updateInterval);

    try {
        const actionInput: CreateKissVideoActionInput = {
            userId: user.uid,
            image1DataUri: img1,
            image2DataUri: mode === 'two' ? img2 : undefined,
        };

        const result = await createKissVideoAction(actionInput);
        
        if (progressIntervalRef.current) clearInterval(progressIntervalRef.current);
        setProgress(100);

        if (result.error) {
            setAppState('form');
            toast({
              variant: 'destructive',
              title: 'Video Generation Failed',
              description: result.error,
              duration: 9000,
            });
        } else if (result.videoDataUri && result.sourceImageDataUri) {
            setVideoUrl(result.videoDataUri);
            setSourceImageUrl(result.sourceImageDataUri);
            setAppState('result');
        }

    } catch(e) {
        console.error("Error during generation action:", e);
        if (progressIntervalRef.current) clearInterval(progressIntervalRef.current);
        setAppState('form');
        const message = e instanceof Error ? e.message : 'An unknown error occurred.';
        toast({ variant: 'destructive', title: 'An Error Occurred', description: `Could not start video generation: ${message}`, duration: 9000 });
    } finally {
        sessionStorage.removeItem('paidAction');
        // Always refresh user profile after any generation attempt.
        if (user) {
            const refreshedProfile = await checkUserSubscription(user.uid);
            setUserProfile(refreshedProfile);
        }
    }
  };
  
  const handleTeaserFlow = () => {
    if (!image1 || (uploadMode === 'two' && !image2)) return;

    // Save images to session storage before showing teaser/paywall
    sessionStorage.setItem('uploadMode', uploadMode);
    sessionStorage.setItem('image1', image1);
    if (uploadMode === 'two' && image2) {
        sessionStorage.setItem('image2', image2);
    }

    setSourceImageUrl(image1);
    
    setAppState('loading');
    setLoadingReason('teaser');
    setProgress(0);

    const teaserDuration = 8000;
    progressIntervalRef.current = setInterval(() => {
        setProgress(prev => Math.min(prev + 100 / (teaserDuration / 100), 100));
    }, 100);

    teaserTimeoutRef.current = setTimeout(() => {
      if (progressIntervalRef.current) clearInterval(progressIntervalRef.current);
      setProgress(100);
      setAppState('teaser');
    }, teaserDuration);
  };
  
  const handleGenerate = () => {
    if (!image1 || (uploadMode === 'single' && !image2 && uploadMode !== 'single')) {
      toast({ variant: 'destructive', title: 'Missing Images', description: 'Please upload all required images.' });
      return;
    }

    // Case 1: User is not logged in.
    if (!user) {
        sessionStorage.setItem('pendingTeaserGeneration', 'true');
        sessionStorage.setItem('uploadMode', uploadMode);
        sessionStorage.setItem('image1', image1);
        if (image2) {
            sessionStorage.setItem('image2', image2);
        }
        router.push('/login?tab=signup');
        return;
    }
    
    // Case 2: User is logged in, subscribed, AND has credits.
    if (userProfile && userProfile.isSubscribed && userProfile.credits > 0) {
      startRealGeneration(image1, image2, uploadMode);
    } else {
      // Case 3: User is logged in but has NOT paid, has no credits, or has only free credit.
      handleTeaserFlow();
    }
  };

  const handleSeeVideo = () => {
    // Images are already saved from handleTeaserFlow
    setIsSubDialogOpen(true);
  };
  
  const handleDownload = () => {
    if (!videoUrl) return;
    const link = document.createElement('a');
    link.href = videoUrl;
    link.download = 'eternal-kiss.mp4';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleReset = () => {
    setAppState('form');
    setImage1(null);
    setImage2(null);
    setSourceImageUrl(null);
    setVideoUrl(null);
    setProgress(0);
    setLoadingReason('generating');
    // Clear session storage related to generation
    sessionStorage.removeItem('pendingTeaserGeneration');
    sessionStorage.removeItem('pendingGeneration');
    sessionStorage.removeItem('paidAction');
    sessionStorage.removeItem('uploadMode');
    sessionStorage.removeItem('image1');
    sessionStorage.removeItem('image2');
  };

  if (authLoading && !user) {
     return (
        <div className="flex items-center justify-center h-full">
            <Loader2 className="h-12 w-12 animate-spin text-primary" />
        </div>
    );
  }

  const getButtonText = () => {
    if (appState === 'loading') return 'Generating...';
    if (userProfile?.isSubscribed && userProfile.credits <= 0) return 'No Credits Remaining';
    return 'Generate Video';
  };
  
  const renderLoadingState = () => (
    <div className="flex flex-col items-center justify-center gap-6 text-center w-full max-w-md">
        <Loader2 className="h-12 w-12 animate-spin text-pink-500" />
        <div className="w-full space-y-2">
            <h2 className="text-2xl font-semibold font-headline">
              {loadingReason === 'teaser' ? 'Creating your moment...' : 'Creating your video...'}
            </h2>
            <p className="text-muted-foreground">
                {loadingReason === 'teaser' ? 'This will just take a moment.' : 'This can take a minute. Please don\'t close this page.'}
            </p>
            <div className="flex items-center gap-2">
              <Progress value={progress} className="w-full" showShimmer={true} />
              <span className="text-sm font-medium text-muted-foreground w-10 text-right">{Math.round(progress)}%</span>
            </div>
        </div>
    </div>
  );

  const renderResultState = () => (
     <Card className="w-full overflow-hidden shadow-2xl bg-gradient-to-br from-purple-50 via-pink-50 to-red-50">
        <CardHeader className="text-center p-6">
            <CardTitle className="text-3xl font-headline bg-gradient-to-r from-pink-500 to-purple-600 bg-clip-text text-transparent">
              Your Kiss is Ready!
            </CardTitle>
            <CardDescription className="text-muted-foreground">
              Here is your moment of magic.
            </CardDescription>
        </CardHeader>

        <CardContent className="p-4 pt-0">
          <div className="relative rounded-lg overflow-hidden border-4 border-white shadow-lg aspect-video">
              {videoUrl ? (
                  <video src={videoUrl} controls autoPlay loop className="w-full h-full object-cover" />
              ) : null}
          </div>
      </CardContent>

      <CardFooter className="p-4 pt-0 flex flex-col sm:flex-row gap-3">
        <Button variant="outline" onClick={handleReset} className="w-full">
          <ArrowLeft className="mr-2 h-4 w-4" />
          Create Another
        </Button>
        {videoUrl && (
          <Button onClick={handleDownload} className="w-full bg-gradient-to-r from-pink-500 to-purple-600 hover:from-pink-600 hover:to-purple-700 text-white">
              <Download className="mr-2 h-4 w-4" />
              Download Video
          </Button>
        )}
      </CardFooter>
    </Card>
  );

  const renderTeaserState = () => (
     <Card className="w-full overflow-hidden shadow-2xl bg-gradient-to-br from-purple-50 via-pink-50 to-red-50">
        <CardHeader className="text-center p-6">
            <CardTitle className="text-3xl font-headline bg-gradient-to-r from-pink-500 to-purple-600 bg-clip-text text-transparent">
              Your Kiss is Ready!
            </CardTitle>
            <CardDescription className="text-muted-foreground">
              Unlock your video to see the magic moment.
            </CardDescription>
        </CardHeader>
        <CardContent className="p-4 pt-0">
          <div className="relative rounded-lg overflow-hidden border-4 border-white shadow-lg aspect-video">
              <Image
                  src={sourceImageUrl || 'https://placehold.co/1280x720.png'}
                  alt="Blurred preview of the generated video"
                  width={1280}
                  height={720}
                  className="w-full h-full object-cover filter blur-lg scale-110"
              />
              <div className="absolute inset-0 bg-black/30 flex items-center justify-center">
                  <Button onClick={handleSeeVideo} size="lg" className="bg-white/20 hover:bg-white/30 text-white backdrop-blur-sm">
                      <Eye className="mr-2 h-5 w-5" />
                      See the Video
                  </Button>
              </div>
          </div>
        </CardContent>
        <CardFooter className="p-4 pt-0">
           <Button variant="outline" onClick={handleReset} className="w-full">
              <ArrowLeft className="mr-2 h-4 w-4" />
              Start Over
            </Button>
        </CardFooter>
      </Card>
  );

  const UserStatusIndicator = () => {
    if (!user) {
        return (
            <div className="flex items-center justify-center gap-2 text-sm text-muted-foreground">
                <Info className="h-4 w-4" />
                <span>Status: Not Logged In</span>
            </div>
        )
    }
    if (userProfile?.isSubscribed && userProfile.credits > 0) {
        return (
            <div className="flex items-center justify-center gap-2 text-sm text-green-600">
                <Info className="h-4 w-4" />
                <span>Status: Subscribed ({userProfile.credits} credits remaining)</span>
            </div>
        )
    }
    if (userProfile?.isSubscribed) {
        return (
            <div className="flex items-center justify-center gap-2 text-sm text-amber-600">
                <Info className="h-4 w-4" />
                <span>Status: Subscribed (0 credits remaining)</span>
            </div>
        );
    }
    // Default to free user status if profile is loaded but not subscribed
    if (userProfile) {
        return (
            <div className="flex items-center justify-center gap-2 text-sm text-amber-600">
                <Info className="h-4 w-4" />
                <span>Status: Free User ({userProfile.credits} credit remaining)</span>
            </div>
        )
    }
    return null;
  }

  return (
    <>
      <SubscriptionDialog
        open={isSubDialogOpen}
        onOpenChange={setIsSubDialogOpen}
       />
        <main className="flex-grow flex items-center justify-center p-4">
          <div className="w-full max-w-xl mx-auto">
            {appState === 'form' && (
              <div className="space-y-6">
                <div className="text-center">
                  <h2 className="text-5xl font-extrabold tracking-tighter bg-gradient-to-r from-pink-500 to-purple-600 bg-clip-text text-transparent">
                    Kiss Your Crush with AI
                  </h2>
                </div>
                <ImageUploader
                  mode={uploadMode}
                  setMode={setUploadMode}
                  image1={image1}
                  setImage1={setImage1}
                  image2={image2}
                  setImage2={setImage2}
                />
                <div className="space-y-3">
                  <Button
                    onClick={handleGenerate}
                    disabled={!canGenerate || appState === 'loading' || (userProfile?.isSubscribed === true && userProfile.credits <= 0)}
                    size="lg"
                    className="w-full bg-gradient-to-r from-pink-500 to-purple-600 hover:from-pink-600 hover:to-purple-700 text-white"
                  >
                     {appState === 'loading' ? <Loader2 className="mr-2 h-5 w-5 animate-spin" /> : <Wand2 className="mr-2 h-5 w-5" />}
                    {getButtonText()}
                  </Button>
                  <UserStatusIndicator />
                </div>
              </div>
            )}

            {appState === 'loading' && renderLoadingState()}
            {appState === 'result' && renderResultState()}
            {appState === 'teaser' && renderTeaserState()}

          </div>
        </main>
    </>
  );
}

export default function Home() {
    return (
        <React.Suspense fallback={
            <div className="flex items-center justify-center h-screen">
                <Loader2 className="h-12 w-12 animate-spin text-primary" />
            </div>
        }>
            <PageContent />
        </React.Suspense>
    );
}

    
